class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF 9 renamed the discriminator property from "Discriminator" to "$type".
            // Preserve the EF 8 property name so existing 500K documents remain readable
            // and direct SQL queries referencing c.Discriminator keep working.
            entity.HasDiscriminator<string>("Discriminator");

            // EF 9 changed the id format from "EntityType|Key" to just "Key".
            // Preserve the EF 8 format so existing documents ("Product|123") stay valid.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id).ToJsonProperty("id")
                  .HasValueGenerator<Microsoft.EntityFrameworkCore.Cosmos.ValueGeneration.IdValueGenerator>();
        });
    }
}
